solution:
function reverseDigits(n) {
  let r = 0;
  while (n > 0) {
    r = r * 10 + (n % 10);
    n = Math.trunc(n / 10);
  }
  return r;
}

function digitSum(n) {
  let s = 0;
  while (n > 0) {
    s += n % 10;
    n = Math.trunc(n / 10);
  }
  return s;
}

