function popcount(x) {
  let c = 0;
  while (x) { x &= x - 1; c++; }
  return c;
}

function buildMask(nums) {
  let m = 0;
  for (let i = 0; i < nums.length; i++) m |= 1 << nums[i];
  return m;
}

